const fs=require\('fs'\),path=require\('path'\),zlib=require\('zlib'\);
// Sum up all chunks needed by the landing page client
// Check how many KB the Three.js chunk is gzipped vs other chunks
const dir='.next/static/chunks';
const chunks=fs.readdirSync\(dir\).filter\(f=>f.endsWith\('.js'\)\);
let total=0;
chunks.forEach\(f=>{
  const buf=fs.readFileSync\(path.join\(dir,f\)\);
  const gz=zlib.gzipSync\(buf\).length;
  total+=gz;
}\);
console.log\('Total gzipped JS chunks:', Math.round\(total/1024\)+'KB'\);
console.log\('Chunk count:', chunks.length\);
// Biggest chunk \(likely Three.js\)
const biggest=chunks.map\(f=>{
  const buf=fs.readFileSync\(path.join\(dir,f\)\);
  return {name:f,gz:zlib.gzipSync\(buf\).length};
}\).sort\(\(a,b\)=>b.gz-a.gz\)[0];
console.log\('Largest chunk:', biggest.name, Math.round\(biggest.gz/1024\)+'KB gz'\);
")
